# vercel.json
vercel = root / 'vercel.json'
config = json.loads(vercel.read_text(encoding='utf-8'))
routes = config.get('routes', [])
api_route = {"src": "/api/(.*)", "dest": "/api/$1"}
if not any(r.get('src') == '/api/(.*)' for r in routes):
    routes.insert(0, api_route)
config['routes'] = routes
vercel.write_text(json.dumps(config, ensure_ascii=False, indent=2) + '\n', encoding='utf-8')

print('auth phase patch applied')
